package format

import (
	"testing"

	"github.com/google/go-cmp/cmp"
	"github.com/zclconf/go-cty/cty"

	"github.com/hashicorp/terraform/internal/addrs"
	"github.com/hashicorp/terraform/internal/plans"
	"github.com/hashicorp/terraform/internal/schemarepo"
	"github.com/hashicorp/terraform/internal/states"
)

func TestCompactDiffFormatter(t *testing.T) {
	tests := map[string]struct {
		plan  *plans.Plan
		want  string
	}{
		"empty plan": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{},
				},
			},
			want: "",
		},
		"no changes": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr:   mustParseAbsResourceInstance("aws_instance.example"),
							Action: plans.NoOp,
						},
					},
				},
			},
			want: "",
		},
		"single create": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr:   mustParseAbsResourceInstance("aws_instance.example"),
							Action: plans.Create,
						},
					},
				},
			},
			want: "[create] aws_instance.example\n\nPlan: 1 to add.\n",
		},
		"single update": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr:   mustParseAbsResourceInstance("aws_instance.example"),
							Action: plans.Update,
						},
					},
				},
			},
			want: "[update] aws_instance.example\n\n1 to change.\n",
		},
		"single delete": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr:   mustParseAbsResourceInstance("aws_instance.example"),
							Action: plans.Delete,
						},
					},
				},
			},
			want: "[delete] aws_instance.example\n\n1 to destroy.\n",
		},
		"multiple resources": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr:   mustParseAbsResourceInstance("aws_instance.web"),
							Action: plans.Create,
						},
						{
							Addr:   mustParseAbsResourceInstance("aws_instance.db"),
							Action: plans.Create,
						},
						{
							Addr:   mustParseAbsResourceInstance("aws_security_group.default"),
							Action: plans.Update,
						},
						{
							Addr:   mustParseAbsResourceInstance("aws_subnet.old"),
							Action: plans.Delete,
						},
					},
				},
			},
			want: "[create] aws_instance.db\n[create] aws_instance.web\n[update] aws_security_group.default\n[delete] aws_subnet.old\n\nPlan: 2 to add, 1 to change, 1 to destroy.\n",
		},
		"replace (DeleteThenCreate)": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr:   mustParseAbsResourceInstance("aws_instance.example"),
							Action: plans.DeleteThenCreate,
						},
					},
				},
			},
			want: "[replace] aws_instance.example\n\n1 to replace.\n",
		},
		"replace (CreateThenDelete)": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr:   mustParseAbsResourceInstance("aws_instance.example"),
							Action: plans.CreateThenDelete,
						},
					},
				},
			},
			want: "[replace] aws_instance.example\n\n1 to replace.\n",
		},
		"read action": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr:   mustParseAbsResourceInstance("data.aws_ami.ubuntu"),
							Action: plans.Read,
						},
					},
				},
			},
			want: "[read] data.aws_ami.ubuntu\n\n1 to read.\n",
		},
		"mixed actions": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr:   mustParseAbsResourceInstance("aws_instance.web[0]"),
							Action: plans.Create,
						},
						{
							Addr:   mustParseAbsResourceInstance("aws_instance.web[1]"),
							Action: plans.Create,
						},
						{
							Addr:   mustParseAbsResourceInstance("aws_db_instance.example"),
							Action: plans.Update,
						},
						{
							Addr:   mustParseAbsResourceInstance("aws_security_group.old"),
							Action: plans.Delete,
						},
						{
							Addr:   mustParseAbsResourceInstance("aws_vpc.main"),
							Action: plans.DeleteThenCreate,
						},
						{
							Addr:   mustParseAbsResourceInstance("data.aws_availability_zones.available"),
							Action: plans.Read,
						},
					},
				},
			},
			want: "[create] aws_instance.web[0]\n[create] aws_instance.web[1]\n[update] aws_db_instance.example\n[delete] aws_security_group.old\n[replace] aws_vpc.main\n[read] data.aws_availability_zones.available\n\nPlan: 2 to add, 1 to change, 1 to replace, 1 to destroy, 1 to read.\n",
		},
		"nil plan": {
			plan: nil,
			want: "",
		},
		"nil changes": {
			plan: &plans.Plan{
				Changes: nil,
			},
			want: "",
		},
	}

	for name, test := range tests {
		t.Run(name, func(t *testing.T) {
			formatter := &CompactDiffFormatter{}
			got := formatter.Format(test.plan, &schemarepo.Schemas{})
			if diff := cmp.Diff(test.want, got); diff != "" {
				t.Errorf("unexpected output:\n%s", diff)
			}
		})
	}
}

// mustParseAbsResourceInstance parses a resource instance address string,
// panicking if it's invalid. This is a helper for test cases.
func mustParseAbsResourceInstance(addr string) addrs.AbsResourceInstance {
	parsed, diags := addrs.ParseAbsResourceInstanceStr(addr)
	if diags.HasErrors() {
		panic(diags.Err())
	}
	return parsed
}

func TestCompactDiffFormatter_EmptyResourceList(t *testing.T) {
	plan := &plans.Plan{
		Changes: &plans.ChangesSrc{
			Resources: nil,
		},
	}
	formatter := &CompactDiffFormatter{}
	result := formatter.Format(plan, &schemarepo.Schemas{})
	if result != "" {
		t.Errorf("expected empty string for nil resources, got: %q", result)
	}
}

func TestCompactDiffFormatter_OnlyNoOp(t *testing.T) {
	plan := &plans.Plan{
		Changes: &plans.ChangesSrc{
			Resources: []*plans.ResourceInstanceChangeSrc{
				{
					Addr:   mustParseAbsResourceInstance("aws_instance.a"),
					Action: plans.NoOp,
				},
				{
					Addr:   mustParseAbsResourceInstance("aws_instance.b"),
					Action: plans.NoOp,
				},
			},
		},
	}
	formatter := &CompactDiffFormatter{}
	result := formatter.Format(plan, &schemarepo.Schemas{})
	if result != "" {
		t.Errorf("expected empty string for only NoOp changes, got: %q", result)
	}
}

func TestCompactDiffFormatter_Sorting(t *testing.T) {
	// Test that resources are sorted alphabetically within each action type
	plan := &plans.Plan{
		Changes: &plans.ChangesSrc{
			Resources: []*plans.ResourceInstanceChangeSrc{
				{
					Addr:   mustParseAbsResourceInstance("aws_instance.zebra"),
					Action: plans.Create,
				},
				{
					Addr:   mustParseAbsResourceInstance("aws_instance.apple"),
					Action: plans.Create,
				},
				{
					Addr:   mustParseAbsResourceInstance("aws_instance.middle"),
					Action: plans.Create,
				},
			},
		},
	}
	formatter := &CompactDiffFormatter{}
	result := formatter.Format(plan, &schemarepo.Schemas{})
	expected := "[create] aws_instance.apple\n[create] aws_instance.middle\n[create] aws_instance.zebra\n\nPlan: 3 to add.\n"
	if diff := cmp.Diff(expected, result); diff != "" {
		t.Errorf("unexpected output:\n%s", diff)
	}
}

func TestCompactDiffFormatter_ResourceInstanceIndexes(t *testing.T) {
	// Test formatting with indexed resource instances
	plan := &plans.Plan{
		Changes: &plans.ChangesSrc{
			Resources: []*plans.ResourceInstanceChangeSrc{
				{
					Addr:   mustParseAbsResourceInstance("aws_instance.web[0]"),
					Action: plans.Create,
				},
				{
					Addr:   mustParseAbsResourceInstance("aws_instance.web[1]"),
					Action: plans.Create,
				},
			},
		},
	}
	formatter := &CompactDiffFormatter{}
	result := formatter.Format(plan, &schemarepo.Schemas{})
	expected := "[create] aws_instance.web[0]\n[create] aws_instance.web[1]\n\nPlan: 2 to add.\n"
	if diff := cmp.Diff(expected, result); diff != "" {
		t.Errorf("unexpected output:\n%s", diff)
	}
}

